  1→import express from "express";
  2→import cors from 'cors';
  3→import compression from "compression";
  4→import helmet from "helmet";
  5→import net from "node:net";
  6→import sharp from "sharp";
  7→import router from "./routes/routes.js";
  8→import supabase from "./services/supabase.js";
  9→
 10→const app = express();
 11→const PORT = process.env.PORT || 3000;
 12→const SITE_URL = 'https://iskrib.com';
 13→const DEFAULT_OG_IMAGE_URL = `${SITE_URL}/assets/no-image.png`;
 14→const DEFAULT_OG_IMAGE_WIDTH = 1200;
 15→const DEFAULT_OG_IMAGE_HEIGHT = 630;
 16→const SOCIAL_PREVIEW_MAX_CHARS = 160;
 17→const REMOTE_IMAGE_FETCH_TIMEOUT_MS = 7000;
 18→const REMOTE_IMAGE_MAX_BYTES = 15 * 1024 * 1024;
 19→const SHARE_IMAGE_FETCH_USER_AGENT = 'IskrybShareBot/1.0 (+https://iskrib.com)';
 20→const META_FB_APP_ID = (process.env.META_FB_APP_ID || process.env.FB_APP_ID || process.env.VITE_FB_APP_ID || '').trim();
 21→const SHARE_IMAGE_DEBUG = false;
 22→const SUPABASE_URL = (process.env.SUPABASE_URL || '').trim();
 23→
 24→const normalizeWhitespace = (value) => String(value ?? '')
 25→    .replace(/\s+/g, ' ')
 26→    .trim();
 27→
 28→const toPreviewText = (value, maxLength = SOCIAL_PREVIEW_MAX_CHARS) => {
 29→    const normalized = normalizeWhitespace(value);
 30→    if (!normalized) return '';
 31→    if (normalized.length <= maxLength) return normalized;
 32→    if (maxLength <= 3) return normalized.slice(0, maxLength);
 33→    return `${normalized.slice(0, maxLength - 3).trimEnd()}...`;
 34→};
 35→
 36→const escHtml = (str) => String(str)
 37→    .replace(/&/g, '&amp;')
 38→    .replace(/</g, '&lt;')
 39→    .replace(/>/g, '&gt;')
 40→    .replace(/"/g, '&quot;');
 41→
 42→const makePostUrl = (journalId, title = '') => {
 43→    const slug = title
 44→        ? title.toLowerCase().trim().replace(/[^a-z0-9\s-]/g, '').replace(/\s+/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '')
 45→        : '';
 46→    return `${SITE_URL}/home/post/${journalId}${slug ? '/' + slug : ''}`;
 47→};
 48→
 49→const getRequestOrigin = (req) => {
 50→    const forwardedProto = String(req.headers['x-forwarded-proto'] || '').split(',')[0].trim().toLowerCase();
 51→    const forwardedHost = String(req.headers['x-forwarded-host'] || '').split(',')[0].trim();
 52→    const host = forwardedHost || req.get('host') || '';
 53→    const requestProtocol = String(req.protocol || '').trim().toLowerCase();
 54→    const protocol = forwardedProto === 'http' || forwardedProto === 'https'
 55→        ? forwardedProto
 56→        : requestProtocol === 'http' || requestProtocol === 'https'
 57→            ? requestProtocol
 58→            : 'https';
 59→
 60→    if (!host) {
 61→        return SITE_URL;
 62→    }
 63→
 64→    return `${protocol}://${host}`;
 65→};
 66→
 67→const pickFirstNonEmptyString = (...values) => {
 68→    for (const value of values) {
 69→        if (typeof value === 'string') {
 70→            const trimmed = value.trim();
 71→            if (trimmed) return trimmed;
 72→        }
 73→    }
 74→    return '';
 75→};
 76→
 77→const parseImageDimension = (value) => {
 78→    const parsed = Number(value);
 79→    if (!Number.isFinite(parsed)) return undefined;
 80→    return parsed;
 81→};
 82→
 83→const imageFromNodeLike = (nodeLike) => {
 84→    if (!nodeLike || typeof nodeLike !== 'object') return null;
 85→
 86→    const src = pickFirstNonEmptyString(
 87→        nodeLike.src,
 88→        nodeLike.url,
 89→        nodeLike.image_url,
 90→        nodeLike.imageUrl,
 91→        nodeLike?.payload?.src,
 92→        nodeLike?.data?.src
 93→    );
 94→    if (!src) return null;
 95→
 96→    return {
 97→        src,
 98→        width: parseImageDimension(nodeLike.width),
 99→        height: parseImageDimension(nodeLike.height),
100→    };
101→};
102→
103→const extractFromLexical = (contentJson) => {
104→    try {
105→        const parsed = typeof contentJson === 'string' ? JSON.parse(contentJson) : contentJson;
106→        const texts = [];
107→        let firstImage = null;
108→
109→        const walk = (node) => {
110→            if (!node || typeof node !== 'object') return;
111→
112→            const nodeType = String(node.type || node.__type || '').trim().toLowerCase();
113→            if (nodeType === 'text' && typeof node.text === 'string') {
114→                texts.push(node.text);
115→            }
116→
117→            const isImageNode = nodeType === 'image' || nodeType.endsWith('image') || nodeType.includes('image');
118→            if (!firstImage && isImageNode) {
119→                const image = imageFromNodeLike(node);
120→                if (image) {
121→                    firstImage = image;
122→                }
123→            }
124→
125→            if (Array.isArray(node.children)) {
126→                node.children.forEach(walk);
127→            }
128→        };
129→
130→        if (parsed?.root) {
131→            walk(parsed.root);
132→        }
133→
134→        return {
135→            text: normalizeWhitespace(texts.join(' ')),
136→            image: firstImage
137→        };
138→    } catch {
139→        return { text: '', image: null };
140→    }
141→};
142→
143→const extractFromCanvasDoc = (canvasDocRaw) => {
144→    try {
145→        const doc = typeof canvasDocRaw === 'string' ? JSON.parse(canvasDocRaw) : canvasDocRaw;
146→        const text = Array.isArray(doc?.snippets)
147→            ? normalizeWhitespace(
148→                doc.snippets
149→                    .map((snippet) => (typeof snippet?.text === 'string' ? snippet.text : ''))
150→                    .join(' ')
151→            )
152→            : '';
153→
154→        let image = null;
155→        if (Array.isArray(doc?.images)) {
156→            const first = doc.images.find((img) => imageFromNodeLike(img));
157→            if (first) image = imageFromNodeLike(first);
158→        }
159→
160→        return { text, image };
161→    } catch {
162→        return { text: '', image: null };
163→    }
164→};
165→
166→const buildShareMetaFromJournal = (journal) => {
167→    const lexicalData = extractFromLexical(journal?.content);
168→    const canvasData = extractFromCanvasDoc(journal?.canvas_doc);
169→    const normalizedTitle = typeof journal?.title === 'string' ? normalizeWhitespace(journal.title) : '';
170→    const title = normalizedTitle || 'Untitled Post';
171→    const authorName = normalizeWhitespace(journal?.users?.name) || 'Someone';
172→
173→    let description = lexicalData.text || '';
174→    if (!description && canvasData.text) {
175→        description = canvasData.text;
176→    }
177→    if (!description) {
178→        description = `Read "${title}" by ${authorName} on Iskryb`;
179→    }
180→
181→    let imageCandidate = DEFAULT_OG_IMAGE_URL;
182→    let imageCandidateSource = 'fallback';
183→    if (lexicalData.image?.src) {
184→        imageCandidate = lexicalData.image.src;
185→        imageCandidateSource = 'lexical';
186→    } else if (canvasData.image?.src) {
187→        imageCandidate = canvasData.image.src;
188→        imageCandidateSource = 'canvas';
189→    } else if (journal?.users?.image_url) {
190→        imageCandidate = journal.users.image_url;
191→        imageCandidateSource = 'author_avatar';
192→    }
193→
194→    return {
195→        title,
196→        normalizedTitle,
197→        description: toPreviewText(description),
198→        imageCandidate,
199→        imageCandidateSource
200→    };
201→};
202→
203→const resolveAbsoluteHttpUrl = (rawUrl) => {
204→    try {
205→        const raw = String(rawUrl || '').trim();
206→        if (!raw) return null;
207→
208→        const isSupabasePath =
209→            raw.startsWith('/storage/v1/object/public/')
210→            || raw.startsWith('storage/v1/object/public/');
211→
212→        const baseUrl = isSupabasePath && SUPABASE_URL
213→            ? `${SUPABASE_URL}/`
214→            : SITE_URL;
215→
216→        const parsed = new URL(raw, baseUrl);
217→        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
218→            return null;
219→        }
220→        return parsed.toString();
221→    } catch {
222→        return null;
223→    }
224→};
225→
226→const isPrivateIpv4Address = (ip) => {
227→    const parts = ip.split('.').map((part) => Number(part));
228→    if (parts.length !== 4 || parts.some((part) => !Number.isInteger(part) || part < 0 || part > 255)) {
229→        return true;
230→    }
231→
232→    const [a, b] = parts;
233→    if (a === 10 || a === 127 || a === 0) return true;
234→    if (a === 169 && b === 254) return true;
235→    if (a === 172 && b >= 16 && b <= 31) return true;
236→    if (a === 192 && b === 168) return true;
237→    return false;
238→};
239→
240→const isPrivateIpv6Address = (ip) => {
241→    const normalized = ip.toLowerCase();
242→    return (
243→        normalized === '::1' ||
244→        normalized.startsWith('fc') ||
245→        normalized.startsWith('fd') ||
246→        normalized.startsWith('fe80:')
247→    );
248→};
249→
250→const isPrivateIpAddress = (ip) => {
251→    const ipVersion = net.isIP(ip);
252→    if (ipVersion === 4) return isPrivateIpv4Address(ip);
253→    if (ipVersion === 6) return isPrivateIpv6Address(ip);
254→    return true;
255→};
256→
257→const isSafeRemoteImageUrl = (imageUrl) => {
258→    try {
259→        const parsed = new URL(imageUrl);
260→        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
261→            return false;
262→        }
263→
264→        const hostname = parsed.hostname.toLowerCase();
265→        if (!hostname || hostname === 'localhost' || hostname.endsWith('.local') || hostname.endsWith('.internal')) {
266→            return false;
267→        }
268→
269→        if (net.isIP(hostname) && isPrivateIpAddress(hostname)) {
270→            return false;
271→        }
272→
273→        return true;
274→    } catch {
275→        return false;
276→    }
277→};
278→
279→const evaluateShareImageCandidate = (rawUrl) => {
280→    const absoluteUrl = resolveAbsoluteHttpUrl(rawUrl);
281→    if (!absoluteUrl) {
282→        return {
283→            ok: false,
284→            reason: 'invalid_or_non_http_url',
285→            resolvedUrl: null,
286→        };
287→    }
288→
289→    let path = '';
290→    try {
291→        const parsed = new URL(absoluteUrl);
292→        path = String(parsed.pathname || '').toLowerCase();
293→    } catch {
294→        return {
295→            ok: false,
296→            reason: 'invalid_resolved_url',
297→            resolvedUrl: null,
298→        };
299→    }
300→
301→    if (path.endsWith('.svg')) {
302→        return {
303→            ok: false,
304→            reason: 'svg_not_supported_for_share_image',
305→            resolvedUrl: absoluteUrl,
306→        };
307→    }
308→
309→    if (!isSafeRemoteImageUrl(absoluteUrl)) {
310→        return {
311→            ok: false,
312→            reason: 'unsafe_remote_url',
313→            resolvedUrl: absoluteUrl,
314→        };
315→    }
316→
317→    return {
318→        ok: true,
319→        reason: 'ok',
320→        resolvedUrl: absoluteUrl,
321→    };
322→};
323→
324→const fetchRemoteImageBuffer = async (imageUrl) => {
325→    const controller = new AbortController();
326→    const timeout = setTimeout(() => controller.abort(), REMOTE_IMAGE_FETCH_TIMEOUT_MS);
327→
328→    try {
329→        const response = await fetch(imageUrl, {
330→            method: 'GET',
331→            redirect: 'follow',
332→            signal: controller.signal,
333→            headers: {
334→                Accept: 'image/*,*/*;q=0.8',
335→                'Accept-Encoding': 'identity',
336→                'User-Agent': SHARE_IMAGE_FETCH_USER_AGENT,
337→            },
338→        });
339→
340→        if (!response.ok) {
341→            throw new Error(`upstream image status ${response.status}`);
342→        }
343→
344→        const finalUrl = response.url || imageUrl;
345→        if (!isSafeRemoteImageUrl(finalUrl)) {
346→            throw new Error('upstream redirected to unsafe url');
347→        }
348→
349→        const contentType = String(response.headers.get('content-type') || '').toLowerCase();
350→        if (!contentType.startsWith('image/')) {
351→            throw new Error(`upstream content-type ${contentType || 'unknown'} is not an image`);
352→        }
353→        if (contentType.includes('image/svg')) {
354→            throw new Error('svg images are not used for share previews');
355→        }
356→
357→        const headerContentLength = Number(response.headers.get('content-length'));
358→        if (Number.isFinite(headerContentLength) && headerContentLength > REMOTE_IMAGE_MAX_BYTES) {
359→            throw new Error(`upstream content-length exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
360→        }
361→
362→        const arrayBuffer = await response.arrayBuffer();
363→        const buffer = Buffer.from(arrayBuffer);
364→
365→        if (!buffer.length) {
366→            throw new Error('upstream image is empty');
367→        }
368→        if (buffer.length > REMOTE_IMAGE_MAX_BYTES) {
369→            throw new Error(`upstream image exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
370→        }
371→
372→        return {
373→            buffer,
374→            contentType,
375→            byteLength: buffer.length,
376→            finalUrl,
377→        };
378→    } finally {
379→        clearTimeout(timeout);
380→    }
381→};
382→
383→const convertToOgJpeg = async (inputBuffer) => {
384→    return sharp(inputBuffer, { limitInputPixels: 60_000_000 })
385→        .rotate()
386→        .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT, {
387→            fit: 'contain',
388→            background: { r: 255, g: 255, b: 255, alpha: 1 },
389→        })
390→        .jpeg({ quality: 82, mozjpeg: true })
391→        .toBuffer();
392→};
393→
394→const getShareJournal = async (journalId) => {
395→    const { data: journal, error } = await supabase
396→        .from('journals')
397→        .select('id, title, content, post_type, canvas_doc, created_at, users(name, image_url)')
398→        .eq('id', journalId)
399→        .single();
400→
401→    if (error || !journal) {
402→        return null;
403→    }
404→
405→    return journal;
406→};
407→
408→const isShareImageDebugRequest = (req) => {
409→    const debugFlag = String(req?.query?.debug || '').trim().toLowerCase();
410→    return SHARE_IMAGE_DEBUG && (debugFlag === '1' || debugFlag === 'true');
411→};
412→
413→const sendShareImageDebug = (res, payload) => {
414→    return res.status(200).json(payload);
415→};
416→
417→const corsOptions = {
418→    origin: ['https://iskrib.com', 'https://iskrib-v3-client-side.onrender.com', 'http://localhost:5173'],
419→    methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
420→    allowedHeaders: ['Content-Type', 'Authorization'],
421→    credentials: true,
422→    maxAge: 60 * 60 * 24
423→};
424→
425→app.use(cors(corsOptions));
426→app.use(compression({ threshold: 1024 }));
427→app.disable("x-powered-by");
428→app.use(
429→    helmet({
430→        contentSecurityPolicy: false,
431→        crossOriginEmbedderPolicy: false,
432→    })
433→);
434→
435→app.use((req, res, next) => {
436→    if (req.method === "GET" && !req.headers.authorization) {
437→        // no-cache: browser must revalidate with server before using cached response.
438→        // This prevents stale data after mutations (likes, comments, replies, etc.)
439→        // while still allowing conditional requests (304 Not Modified) for performance.
440→        // React Query handles client-side caching, so browser cache is unnecessary.
441→        res.set("Cache-Control", "no-cache");
442→    }
443→    next();
444→});
445→
446→app.use(express.json({ limit: "2mb" }));
447→app.use(express.urlencoded({extended: true, limit: "2mb", parameterLimit: 1000}));
448→
449→// ── Share route: serves OG meta tags for social media previews ──
450→app.get('/share/post/:journalId/image', async (req, res) => {
451→    const { journalId } = req.params;
452→    const debugMode = isShareImageDebugRequest(req);
453→    const debugPayload = {
454→        ok: false,
455→        fallback: false,
456→        journalId,
457→        stage: 'start',
458→        reason: '',
459→        meta: {
460→            imageCandidateSource: null,
461→            imageCandidateRaw: null,
462→            imageCandidateResolved: null,
463→            upstreamFinalUrl: null,
464→            upstreamContentType: null,
465→            upstreamBytes: null,
466→            outputBytes: null,
467→        },
468→    };
469→
470→    const fallbackWithReason = (reason) => {
471→        debugPayload.ok = false;
472→        debugPayload.fallback = true;
473→        debugPayload.stage = 'fallback';
474→        debugPayload.reason = reason;
475→        if (debugMode) {
476→            return sendShareImageDebug(res, debugPayload);
477→        }
478→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
479→    };
480→
481→    try {
482→        const journal = await getShareJournal(journalId);
483→        debugPayload.stage = 'journal_loaded';
484→        if (!journal) {
485→            return fallbackWithReason('journal_not_found');
486→        }
487→
488→        const shareMeta = buildShareMetaFromJournal(journal);
489→        debugPayload.stage = 'candidate_extracted';
490→        debugPayload.meta.imageCandidateSource = shareMeta.imageCandidateSource;
491→        debugPayload.meta.imageCandidateRaw = shareMeta.imageCandidate;
492→
493→        const candidateEvaluation = evaluateShareImageCandidate(shareMeta.imageCandidate);
494→        debugPayload.meta.imageCandidateResolved = candidateEvaluation.resolvedUrl;
495→        if (!candidateEvaluation.ok || !candidateEvaluation.resolvedUrl) {
496→            return fallbackWithReason(candidateEvaluation.reason);
497→        }
498→
499→        const normalizedFallbackUrl = new URL(DEFAULT_OG_IMAGE_URL).toString();
500→        if (candidateEvaluation.resolvedUrl === normalizedFallbackUrl) {
501→            return fallbackWithReason('candidate_is_default_fallback');
502→        }
503→
504→        debugPayload.stage = 'fetching_upstream';
505→        const remoteImage = await fetchRemoteImageBuffer(candidateEvaluation.resolvedUrl);
506→        debugPayload.stage = 'upstream_loaded';
507→        debugPayload.meta.upstreamFinalUrl = remoteImage.finalUrl;
508→        debugPayload.meta.upstreamContentType = remoteImage.contentType;
509→        debugPayload.meta.upstreamBytes = remoteImage.byteLength;
510→
511→        debugPayload.stage = 'converting_image';
512→        const ogImageBuffer = await convertToOgJpeg(remoteImage.buffer);
513→        debugPayload.stage = 'converted_image';
514→        debugPayload.ok = true;
515→        debugPayload.reason = 'ok';
516→        debugPayload.meta.outputBytes = ogImageBuffer.length;
517→
518→        if (debugMode) {
519→            return sendShareImageDebug(res, debugPayload);
520→        }
521→
522→        res.set('Content-Type', 'image/jpeg');
523→        res.set('Cache-Control', 'public, max-age=3600');
524→        return res.send(ogImageBuffer);
525→    } catch (err) {
526→        debugPayload.stage = 'error';
527→        debugPayload.reason = err?.message || 'unknown_error';
528→        console.error('share image route error:', err?.message || err);
529→        return fallbackWithReason(debugPayload.reason);
530→    }
531→});
532→
533→app.get('/share/post/:journalId', async (req, res) => {
534→    const { journalId } = req.params;
535→    const shareOrigin = getRequestOrigin(req);
536→    const buildRedirectUrl = (title = '') => makePostUrl(journalId, title);
537→
538→    try {
539→        const journal = await getShareJournal(journalId);
540→        if (!journal) {
541→            return res.redirect(302, buildRedirectUrl(''));
542→        }
543→
544→        const shareMeta = buildShareMetaFromJournal(journal);
545→        const clientPostUrl = buildRedirectUrl(shareMeta.normalizedTitle);
546→        const shareImageUrl = new URL(`/share/post/${journalId}/image`, `${shareOrigin}/`).toString();
547→        const fbAppIdTag = META_FB_APP_ID
548→            ? `<meta property="fb:app_id" content="${escHtml(META_FB_APP_ID)}">`
549→            : '';
550→
551→        const html = `<!DOCTYPE html>
552→<html lang="en">
553→<head>
554→<meta charset="utf-8">
555→<title>${escHtml(shareMeta.title)} | Iskryb</title>
556→<meta name="description" content="${escHtml(shareMeta.description)}">
557→${fbAppIdTag}
558→<link rel="canonical" href="${escHtml(clientPostUrl)}">
559→<meta property="og:type" content="article">
560→<meta property="og:title" content="${escHtml(shareMeta.title)}">
561→<meta property="og:description" content="${escHtml(shareMeta.description)}">
562→<meta property="og:image" content="${escHtml(shareImageUrl)}">
563→<meta property="og:image:width" content="${String(DEFAULT_OG_IMAGE_WIDTH)}">
564→<meta property="og:image:height" content="${String(DEFAULT_OG_IMAGE_HEIGHT)}">
565→<meta property="og:url" content="${escHtml(clientPostUrl)}">
566→<meta property="og:site_name" content="Iskryb">
567→<meta name="twitter:card" content="summary_large_image">
568→<meta name="twitter:title" content="${escHtml(shareMeta.title)}">
569→<meta name="twitter:description" content="${escHtml(shareMeta.description)}">
570→<meta name="twitter:image" content="${escHtml(shareImageUrl)}">
571→<meta name="twitter:image:width" content="${String(DEFAULT_OG_IMAGE_WIDTH)}">
572→<meta name="twitter:image:height" content="${String(DEFAULT_OG_IMAGE_HEIGHT)}">
573→<script>
574→window.location.replace(${JSON.stringify(clientPostUrl)});
575→</script>
576→</head>
577→<body>
578→<p>${escHtml(shareMeta.title)} - Redirecting to Iskryb...</p>
579→<a href="${escHtml(clientPostUrl)}">Click here if not redirected</a>
580→</body>
581→</html>`;
582→
583→        res.set('Content-Type', 'text/html; charset=utf-8');
584→        return res.send(html);
585→    } catch (err) {
586→        console.error('share route error:', err?.message || err);
587→        return res.redirect(302, buildRedirectUrl(''));
588→    }
589→});
590→
591→// Also handle /api/share/post/:journalId so getShareUrl works in both configurations
592→app.get('/api/share/post/:journalId/image', (req, res) => {
593→    res.redirect(301, `/share/post/${req.params.journalId}/image`);
594→});
595→
596→app.get('/api/share/post/:journalId', (req, res) => {
597→    res.redirect(301, `/share/post/${req.params.journalId}`);
598→});
599→
600→app.use('/api', router);
601→// Keep legacy root routes available while clients migrate to /api.
602→app.use(router)
603→
604→app.get('/', (req, res) => {
605→    res.send(`hello from backend port ${PORT}`)
606→})
607→
608→app.use((req, res) => {
609→    res.status(404).json({ error: "not found" });
610→});
611→
612→app.use((err, _req, res, _next) => {
613→    console.error("unhandled server error:", err?.message || err);
614→    res.status(500).json({ error: "internal server error" });
615→});
616→
617→app.listen(PORT, () =>{
618→    console.log(`server is running at port${PORT}`)
619→})
