23→  </url>`;
24→  })
25→  .join("\n");
26→
27→const sitemap = `<?xml version="1.0" encoding="UTF-8"?>
28→<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">
29→${urlEntries}
30→</urlset>
31→`;
32→
33→const outputPath = path.resolve(process.cwd(), "public", "sitemap.xml");
34→await fs.writeFile(outputPath, sitemap, "utf8");
35→
36→console.log(`Generated sitemap: ${outputPath}`);
