 30→const replaceSeo = (html, pathname) => {
 31→  const seo = getSeoForPath(pathname);
 32→  const canonicalUrl = buildAbsoluteUrl(seo.canonicalPath || pathname);
 33→  const ogTitle = seo.ogTitle || seo.title;
 34→  const ogDescription = seo.ogDescription || seo.description;
 35→  const ogImage = seo.ogImage || DEFAULT_OG_IMAGE;
 36→  const fbAppId = String(process.env.VITE_FB_APP_ID || "").trim();
 37→
 38→  let updated = html.replace(/<title>[\s\S]*?<\/title>/i, `<title>${escapeHtml(seo.title)}</title>`);
 39→
 40→  updated = replaceOrInsert(
 41→    updated,
 42→    /<meta[^>]*id=["']seo-description["'][^>]*>/i,
 43→    `<meta id="seo-description" name="description" content="${escapeHtml(seo.description)}" />`
 44→  );
 45→  updated = replaceOrInsert(
 46→    updated,
 47→    /<meta[^>]*id=["']seo-robots["'][^>]*>/i,
 48→    `<meta id="seo-robots" name="robots" content="${escapeHtml(seo.robots || "index,follow")}" />`
 49→  );
 50→  updated = replaceOrInsert(
 51→    updated,
 52→    /<link[^>]*id=["']seo-canonical["'][^>]*>/i,
 53→    `<link id="seo-canonical" rel="canonical" href="${canonicalUrl}" />`
 54→  );
 55→  updated = replaceOrInsert(
 56→    updated,
 57→    /<link[^>]*id=["']seo-hreflang-en["'][^>]*>/i,
 58→    `<link id="seo-hreflang-en" rel="alternate" hreflang="en-US" href="${canonicalUrl}" />`
 59→  );
 60→  updated = replaceOrInsert(
 61→    updated,
 62→    /<link[^>]*id=["']seo-hreflang-default["'][^>]*>/i,
 63→    `<link id="seo-hreflang-default" rel="alternate" hreflang="x-default" href="${canonicalUrl}" />`
 64→  );
 65→
 66→  updated = replaceOrInsert(
 67→    updated,
 68→    /<meta[^>]*id=["']seo-og-type["'][^>]*>/i,
 69→    `<meta id="seo-og-type" property="og:type" content="website" />`
 70→  );
 71→  updated = replaceOrInsert(
 72→    updated,
 73→    /<meta[^>]*id=["']seo-og-url["'][^>]*>/i,
 74→    `<meta id="seo-og-url" property="og:url" content="${canonicalUrl}" />`
 75→  );
 76→  updated = replaceOrInsert(
 77→    updated,
 78→    /<meta[^>]*id=["']seo-og-title["'][^>]*>/i,
 79→    `<meta id="seo-og-title" property="og:title" content="${escapeHtml(ogTitle)}" />`
 80→  );
 81→  updated = replaceOrInsert(
 82→    updated,
 83→    /<meta[^>]*id=["']seo-og-description["'][^>]*>/i,
 84→    `<meta id="seo-og-description" property="og:description" content="${escapeHtml(ogDescription)}" />`
 85→  );
 86→  updated = replaceOrInsert(
 87→    updated,
 88→    /<meta[^>]*id=["']seo-og-image["'][^>]*>/i,
 89→    `<meta id="seo-og-image" property="og:image" content="${ogImage}" />`
 90→  );
 91→  updated = replaceOrInsert(
 92→    updated,
 93→    /<meta[^>]*id=["']seo-og-image-width["'][^>]*>/i,
 94→    `<meta id="seo-og-image-width" property="og:image:width" content="${String(DEFAULT_OG_IMAGE_WIDTH)}" />`
 95→  );
 96→  updated = replaceOrInsert(
 97→    updated,
 98→    /<meta[^>]*id=["']seo-og-image-height["'][^>]*>/i,
 99→    `<meta id="seo-og-image-height" property="og:image:height" content="${String(DEFAULT_OG_IMAGE_HEIGHT)}" />`
100→  );
101→  if (fbAppId) {
102→    updated = replaceOrInsert(
103→      updated,
104→      /<meta[^>]*id=["']seo-fb-app-id["'][^>]*>/i,
105→      `<meta id="seo-fb-app-id" property="fb:app_id" content="${escapeHtml(fbAppId)}" />`
106→    );
107→  } else {
108→    updated = updated.replace(/<meta[^>]*id=["']seo-fb-app-id["'][^>]*>\s*/i, "");
109→  }
110→  updated = replaceOrInsert(
111→    updated,
112→    /<meta[^>]*id=["']seo-twitter-card["'][^>]*>/i,
113→    `<meta id="seo-twitter-card" name="twitter:card" content="summary_large_image" />`
114→  );
115→  updated = replaceOrInsert(
116→    updated,
117→    /<meta[^>]*id=["']seo-twitter-title["'][^>]*>/i,
118→    `<meta id="seo-twitter-title" name="twitter:title" content="${escapeHtml(ogTitle)}" />`
119→  );
120→  updated = replaceOrInsert(
121→    updated,
122→    /<meta[^>]*id=["']seo-twitter-description["'][^>]*>/i,
123→    `<meta id="seo-twitter-description" name="twitter:description" content="${escapeHtml(ogDescription)}" />`
124→  );
125→  updated = replaceOrInsert(
126→    updated,
127→    /<meta[^>]*id=["']seo-twitter-image["'][^>]*>/i,
128→    `<meta id="seo-twitter-image" name="twitter:image" content="${ogImage}" />`
129→  );
130→  updated = replaceOrInsert(
131→    updated,
132→    /<meta[^>]*id=["']seo-twitter-image-width["'][^>]*>/i,
133→    `<meta id="seo-twitter-image-width" name="twitter:image:width" content="${String(DEFAULT_OG_IMAGE_WIDTH)}" />`
134→  );
135→  updated = replaceOrInsert(
136→    updated,
137→    /<meta[^>]*id=["']seo-twitter-image-height["'][^>]*>/i,
138→    `<meta id="seo-twitter-image-height" name="twitter:image:height" content="${String(DEFAULT_OG_IMAGE_HEIGHT)}" />`
139→  );
140→
141→  const websiteSchema = JSON.stringify(buildWebsiteSchema(canonicalUrl));
142→  const organizationSchema = JSON.stringify(ORGANIZATION_SCHEMA);
143→  updated = replaceOrInsert(
144→    updated,
145→    /<script[^>]*id=["']seo-ld-website["'][^>]*>[\s\S]*?<\/script>/i,
146→    `<script id="seo-ld-website" type="application/ld+json">${websiteSchema}</script>`
147→  );
148→  updated = replaceOrInsert(
149→    updated,
150→    /<script[^>]*id=["']seo-ld-organization["'][^>]*>[\s\S]*?<\/script>/i,
151→    `<script id="seo-ld-organization" type="application/ld+json">${organizationSchema}</script>`
152→  );
153→
154→  return updated;
155→};
